const msg = $input.first().json.body.message || $input.first().json.message || {};
const call = msg.call || {};
const analysis = msg.analysis || {};

const duration = msg.durationSeconds || 0;
const summary = analysis.summary || '';
const sentiment = analysis.successEvaluation || 'unknown';
const callId = call.id || 'unknown';
const endedReason = msg.endedReason || '';
const isWarmLead = duration > 90;
const isNoAnswer = duration < 15;

return [{
  json: {
    callId,
    duration,
    summary,
    sentiment,
    endedReason,
    isWarmLead,
    isNoAnswer,
    timestamp: new Date().toISOString()
  }
}];

