const fs = require('fs');
const QUEUE_PATH = '/root/.openclaw/workspace/assets/call-queue.json';

let queue = [];
try { queue = JSON.parse(fs.readFileSync(QUEUE_PATH, 'utf8')); } catch(e) { queue = []; }

const callId = $input.first().json.callId;
const entry = queue.find(c => c.call_id === callId || c.id === callId);
if (entry) {
  entry.status = $input.first().json.isWarmLead ? 'warm_lead' : 
                 $input.first().json.isNoAnswer ? 'no_answer' : 'completed';
  entry.completed_at = new Date().toISOString();
  entry.duration = $input.first().json.duration;
  entry.summary = $input.first().json.summary;
} else {
  queue.push({
    call_id: callId,
    status: $input.first().json.isWarmLead ? 'warm_lead' : 
            $input.first().json.isNoAnswer ? 'no_answer' : 'completed',
    completed_at: new Date().toISOString(),
    duration: $input.first().json.duration,
    summary: $input.first().json.summary
  });
}

fs.writeFileSync(QUEUE_PATH, JSON.stringify(queue, null, 2));
return $input.all();

// Queue follow-up email for tomorrow 9am
const fs = require('fs');
const QUEUE_PATH = '/root/.openclaw/workspace/assets/email-queue.json';

let emailQueue = [];
try { emailQueue = JSON.parse(fs.readFileSync(QUEUE_PATH, 'utf8')); } catch(e) { emailQueue = []; }

const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
tomorrow.setHours(9, 0, 0, 0);

const item = $input.first().json;
emailQueue.push({
  type: 'follow_up',
  call_id: item.callId,
  scheduled_for: tomorrow.toISOString(),
  subject: 'Following up on our conversation',
  notes: item.summary,
  status: 'pending'
});

fs.writeFileSync(QUEUE_PATH, JSON.stringify(emailQueue, null, 2));
return [{ json: { queued: true, scheduled_for: tomorrow.toISOString() } }];
